// Get cart items and user details
const cartItems = $input.all().map(item => item.json);
const userData = $('Split In Batches').item.json;
const emailType = userData.email_to_send;
const firstName = userData.first_name || 'Customer';
const recipientEmail = userData.recipient_email;

// Helper function to format currency
const formatCurrency = (amount) => {
  const num = parseFloat(amount) || 0;
  return '₱' + num.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
};

// Find the most recent item by created_at (since updated_at gets overwritten on email logs)
const sortedItems = cartItems
  .filter(item => item.cart_item_id)
  .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

const mostRecentItem = sortedItems[0];

if (!mostRecentItem) {
  return [{
    json: {
      sendEmail: false,
      userId: userData.user_id,
      emailType: emailType
    }
  }];
}

// Build cart items HTML and text for the single most recent item
const itemName = `${mostRecentItem.cake_size || '4"'} ${mostRecentItem.cake_type || 'Round'}, ${mostRecentItem.cake_thickness || '2 in thickness'}`;
const qty = mostRecentItem.quantity || 1;
const price = parseFloat(mostRecentItem.final_price) || 0;
const subtotal = price * qty;

const imageUrl = mostRecentItem.customized_image_url || mostRecentItem.original_image_url || 'https://cqmhanqnfybyxezhobkx.supabase.co/storage/v1/object/public/cakegenie/placeholder-cake.jpg';
const flavor = mostRecentItem.customization_details?.flavors?.[0] || mostRecentItem.customization_details?.flavor || 'Custom flavor';

const itemsHtml = `
<tr>
  <td style="padding: 12px; border-bottom: 1px solid #ddd;">
    <div style="display: flex; align-items: center;">
      <img src="${imageUrl}" alt="Cake design" style="width: 80px; height: 80px; object-fit: cover; border-radius: 8px; margin-right: 12px; display: block;" />
      <div>
        <strong>${itemName}</strong>
        <br><small style="color: #666;">Flavor: ${flavor}</small>
      </div>
    </div>
  </td>
  <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: center;">${qty}</td>
  <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: right;">${formatCurrency(price)}</td>
  <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: right;">${formatCurrency(subtotal)}</td>
</tr>`;

const itemsText = `${itemName} x ${qty} - ${formatCurrency(subtotal)}\n`;

// 20% discount calculations (18hr email only)
const DISCOUNT_CODE = 'NEW20';
const DISCOUNT_RATE = 0.20;
const discountAmount = subtotal * DISCOUNT_RATE;
const discountedTotal = subtotal - discountAmount;

// Tailor email copy based on type (100 min vs 18 hour)
const isFirstEmail = emailType === '100_min';

const subject = isFirstEmail
  ? `✨ We've saved your custom cake design, ${firstName}! ✨`
  : `🎉 ${firstName}, here's 20% off your saved cake — use code NEW20!`;

const headerTitle = isFirstEmail
  ? `Your custom design is waiting!`
  : `Here's 20% off — just for you, ${firstName}! 🎉`;

const introductoryCopy = isFirstEmail
  ? `We noticed you left some custom creations in your cart. Your dream cake is still saved and ready for you to complete!`
  : `We noticed you still have a custom cake waiting in your cart. We'd love to make it a little sweeter — enjoy 20% off your order when you check out today!`;

// Discount banner HTML (18hr only)
const discountBannerHtml = isFirstEmail ? '' : `
<div style="background: linear-gradient(135deg, #ff6b6b 0%, #ee5a24 100%); border-radius: 12px; padding: 24px; text-align: center; margin: 24px 0;">
  <p style="margin: 0 0 6px; color: #fff; font-size: 14px; letter-spacing: 1px; text-transform: uppercase; font-weight: 600;">⏰ Limited-Time Offer</p>
  <p style="margin: 0 0 12px; color: #fff; font-size: 28px; font-weight: 900;">20% OFF YOUR ORDER</p>
  <p style="margin: 0 0 16px; color: rgba(255,255,255,0.9); font-size: 15px;">Use this code at checkout:</p>
  <div style="display: inline-block; background: #fff; border-radius: 8px; padding: 12px 28px; margin-bottom: 16px;">
    <span style="font-size: 26px; font-weight: 900; color: #ee5a24; letter-spacing: 4px;">NEW20</span>
  </div>
  <table style="width: 100%; border-top: 1px solid rgba(255,255,255,0.3); margin-top: 16px; padding-top: 16px;">
    <tr>
      <td style="padding: 6px 0; color: rgba(255,255,255,0.85); font-size: 14px; text-align: left;">Original subtotal</td>
      <td style="padding: 6px 0; color: rgba(255,255,255,0.85); font-size: 14px; text-align: right; text-decoration: line-through;">${formatCurrency(subtotal)}</td>
    </tr>
    <tr>
      <td style="padding: 6px 0; color: #ffe066; font-size: 14px; text-align: left;">Your 20% discount (NEW20)</td>
      <td style="padding: 6px 0; color: #ffe066; font-size: 14px; text-align: right; font-weight: bold;">- ${formatCurrency(discountAmount)}</td>
    </tr>
    <tr>
      <td style="padding: 8px 0 0; color: #fff; font-size: 18px; font-weight: 900; text-align: left; border-top: 1px solid rgba(255,255,255,0.3);">You pay</td>
      <td style="padding: 8px 0 0; color: #fff; font-size: 18px; font-weight: 900; text-align: right; border-top: 1px solid rgba(255,255,255,0.3);">${formatCurrency(discountedTotal)}</td>
    </tr>
  </table>
</div>`;

// Discount text block (18hr only)
const discountTextBlock = isFirstEmail ? '' : `🎉 EXCLUSIVE DISCOUNT FOR YOU 🎉\n\nUse code NEW20 at checkout to get 20% off!\n\nOriginal subtotal: ${formatCurrency(subtotal)}\nYour 20% discount: - ${formatCurrency(discountAmount)}\nYou pay: ${formatCurrency(discountedTotal)}\n\n`;

const ctaLabel = isFirstEmail ? '✨ Return and Checkout Now' : '🎉 Claim My 20% Off Now';

// Build HTML email
const htmlContent = `<!DOCTYPE html><html><head><meta charset='UTF-8'><meta name='viewport' content='width=device-width,initial-scale=1.0'><style>body{font-family:Arial,sans-serif;line-height:1.6;color:#333;margin:0;padding:0}.container{max-width:600px;margin:0 auto;padding:0}.logo-header{text-align:center;padding:30px 20px;background:#fff}.logo-header img{max-width:280px;height:auto;display:block;margin:0 auto}.header{background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);color:white;padding:30px;text-align:center;border-radius:10px 10px 0 0}.content{background:#fff;padding:30px;border:1px solid #e0e0e0;border-top:none;border-radius:0 0 10px 10px}.section{margin:20px 0}.section-title{font-size:18px;font-weight:bold;color:#667eea;margin-bottom:10px;border-bottom:2px solid #667eea;padding-bottom:5px}.footer{text-align:center;padding:20px;color:#666;font-size:14px}.btn-primary{display:inline-block;padding:12px 24px;background:#667eea;color:#ffffff !important;text-decoration:none;font-weight:bold;border-radius:8px;margin:20px 0;text-align:center}.btn-discount{display:inline-block;padding:14px 32px;background:linear-gradient(135deg,#ff6b6b 0%,#ee5a24 100%);color:#ffffff !important;text-decoration:none;font-weight:900;border-radius:8px;margin:20px 0;text-align:center;font-size:16px}</style></head><body><div class='container'><div class='logo-header'><img src='https://cqmhanqnfybyxezhobkx.supabase.co/storage/v1/object/public/landingpage/new%20genie%20logo%20long.jpg' alt='Genie.ph'></div><div class='header'><h1 style='margin:0;font-size:26px'>${headerTitle}</h1></div><div class='content'><p>Hi <strong>${firstName}</strong>,</p><p>${introductoryCopy}</p>${discountBannerHtml}<div class='section'><div class='section-title'>🎂 Saved in Your Cart</div><table style="width: 100%; border-collapse: collapse; margin: 20px 0;"><thead><tr style="background-color: #f8f9fa;"><th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: left;">Item Details</th><th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: center; width: 80px;">Qty</th><th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: right; width: 100px;">Price</th><th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: right; width: 100px;">Total</th></tr></thead><tbody>${itemsHtml}</tbody><tfoot><tr><td colspan="3" style="padding: 12px; text-align: right; font-weight: bold; border-top: 2px solid #dee2e6;">Estimated Subtotal:</td><td style="padding: 12px; text-align: right; font-weight: bold; border-top: 2px solid #dee2e6; color: #28a745;">${formatCurrency(subtotal)}</td></tr></tfoot></table></div><div style="text-align: center;"><a href="https://genie.ph/cart" class="${isFirstEmail ? 'btn-primary' : 'btn-discount'}" style="color:#ffffff !important;">${ctaLabel}</a></div><div style='background:#f8f9fa;padding:20px;border-radius:8px;margin:20px 0'><p style='margin:0;font-size:14px;color:#666'><strong>Need assistance?</strong><br>If you run into any issues checking out or have questions about customized designs, reply to this email or contact us at <strong>09089408747</strong>.</p></div><p style='text-align:center;color:#666;margin:0'>From the Genie.ph Team</p></div><div class='footer'><p>This email was sent to ${recipientEmail} because you have items in your Genie.ph cart.</p><p>© 2025 Genie.ph - Making celebrations magical, one cake at a time ✨</p></div></div></body></html>`;

const textContent = `${isFirstEmail ? '✨ YOUR SAVED CART AT GENIE.PH ✨' : '🎉 20% OFF YOUR SAVED CAKE AT GENIE.PH 🎉'}\n\nHi ${firstName},\n\n${introductoryCopy}\n\n${discountTextBlock}🎂 Items in Your Cart:\n${itemsText}\nEstimated Subtotal: ${formatCurrency(subtotal)}\n\n${isFirstEmail ? '' : 'Apply code NEW20 at checkout to save ' + formatCurrency(discountAmount) + ' — you pay only ' + formatCurrency(discountedTotal) + '.\\n\\n'}Return to your cart to check out here: https://genie.ph/cart\n\nNeed Help?\nReply directly to this email or call us at 09089408747.\n\nFrom the Genie.ph Team`;

return [{
  json: {
    sendEmail: true,
    recipientEmail: recipientEmail,
    recipientName: firstName,
    subject: subject,
    htmlContent: htmlContent,
    textContent: textContent,
    userId: userData.user_id,
    emailType: emailType
  }
}];
